export function getWashingtonWeightLossClinicsByCity(citySlug: string): WeightLossClinic[] {
  return washingtonWeightLossClinics.filter(c => c.citySlug === citySlug);
}

export function getWashingtonWeightLossCitiesWithClinics(): { city: string; citySlug: string; count: number }[] {
  const map = new Map<string, { city: string; citySlug: string; count: number }>();
  for (const c of washingtonWeightLossClinics) {
    const e = map.get(c.citySlug) || { city: c.city, citySlug: c.citySlug, count: 0 };
    e.count++; map.set(c.citySlug, e);
  }
  return Array.from(map.values());
}
